    }

    /* Mirror result. */
    for (index = 0; index < *pathsize / 2; index++)
    {
        unsigned short temp = (*path)[index];
        (*path)[index] = (*path)[*pathsize - index - 1];
        (*path)[*pathsize - index - 1] = temp;
    }
}

